  // signal name changes

  assign up_clk = s_axi_aclk;
  assign up_rstn = s_axi_aresetn;

  // trigger logic

  assign low_level  = trigger_config[1:0];
  assign high_level = trigger_config[3:2];
  assign any_edge   = trigger_config[5:4];
