+                             dma_valid & dma_valid_adjacent :
+                             dma_valid;
+  assign transfer_start = !(en_start_trigger ^ trigger) & transfer_ready;
+
   always @(posedge dac_clk) begin
-    if (dma_transfer_suspend == 1'b0) begin
