+  end
+
+  // transfer state machine
+  always @(posedge dac_clk) begin
+    case (transfer_sm)
+      IDLE: begin
+        transfer <= 1'b0;
+        if (dac_int_ready) begin
+          transfer_sm_next <= WAIT;
+        end
+      end
+      WAIT: begin
+        transfer <= 1'b0;
+        if (transfer_start) begin
